            <Fragment key={msg.id}>
              <div>{msg.title}</div>
            </Fragment>
          ))}
        </Fragment>
      ))}
      <div>
        <button
          onClick={() => q.fetchNextPage()}
          disabled={!q.hasNextPage || q.isFetchingNextPage}
          data-testid="loadMore"
        >
          {q.isFetchingNextPage
            ? 'Loading more...'
            : q.hasNextPage
              ? 'Load More'
              : 'Nothing more to load'}
        </button>
      </div>
      <div>
        {q.isFetching && !q.isFetchingNextPage ? 'Fetching...' : null}
      </div>
    </>
  );
}

