  const abortState: Record<number, 'aborted'> = {};

  const ee = new EventEmitter();
  const t = initTRPC.create({
    errorFormatter({ shape }) {
      return {
        ...shape,
        data: {
          ...shape.data,
          foo: 'bar' as const,
        },
      };
    },
  });
  const appRouter = t.router({
    onEventIterable: t.procedure
      .input(z.number())
      .subscription(async function* (opts) {
        try {
          for await (const event of on(ee, 'data', {
            signal: opts.signal,
          })) {
            const data = event[0] as number;
            yield data + opts.input;
          }
        } catch (err) {
          if (isAbortError(err)) {
            abortState[opts.input] = 'aborted';
          }
          throw err;
        }
      }),
    /**
     * @deprecated delete in v12
     */
    onEventObservable: t.procedure
      .input(z.number())
      .subscription(({ input }) => {
        return observable<number>((emit) => {
          const onData = (data: number) => {
            emit.next(data + input);
          };
          ee.on('data', onData);
          return () => {
            ee.off('data', onData);
          };
        });
      }),
  });

  const ctx = testReactResource(appRouter, {
    client(opts) {
      return {
        links: [
          protocol === 'http'
            ? httpSubscriptionLink({
                url: opts.httpUrl,
              })
            : wsLink({
                client: opts.wsClient,
              }),
        ],
      };
    },
  });

  return {
    ...ctx,
    ee,
    abortState,
  };
}

